import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.7R1OEGYz.js";const p=JSON.parse('{"title":"Your Card","description":"","frontmatter":{},"headers":[],"relativePath":"using/card.md","filePath":"using/card.md"}'),i={name:"using/card.md"};function s(n,e,d,h,l,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="your-card" tabindex="-1">Your Card <a class="header-anchor" href="#your-card" aria-label="Permalink to &quot;Your Card&quot;">​</a></h1><p>The Suho Card is an attested identity card. Your account signs it. The seal attests the human. The fields are your own claims.</p><h2 id="what-the-card-holds" tabindex="-1">What the card holds <a class="header-anchor" href="#what-the-card-holds" aria-label="Permalink to &quot;What the card holds&quot;">​</a></h2><ul><li>A display name, a contact, and a remarks line.</li><li>The red seal, if your account is Dojang-verified.</li><li>Your up.id name.</li><li>A version number and the attestation id.</li><li>A QR code linking to your account on the explorer.</li></ul><p>The card renders at credit-card proportion. It carries one honest line in small print: identity is verified by Dojang; card fields are self-declared by the verified owner. The seal attests the human. The fields are their claims. Do not blur the two.</p><h2 id="how-versions-work" tabindex="-1">How versions work <a class="header-anchor" href="#how-versions-work" aria-label="Permalink to &quot;How versions work&quot;">​</a></h2><p>The card is an attestation on EAS, made by your account itself. Not by a guardian key. Every version is passkey-signed.</p><p>An edit is one batch: attest the new version, then revoke the old one. The two happen together. Nothing is ever deleted. The new attestation points at the old one, so the version history is a walkable chain.</p><p>The Versions panel shows each version with its timestamp. The current one is a filled seal dot. A revoked one is a hollow dot with its revocation time.</p><p>A self-attested card is proven live. <a href="https://sepolia-explorer.giwa.io/tx/0x5cbfba2ea0e076948d6eeb411c349f47cb0b4fa91339cf3321098e1df08ab167" target="_blank" rel="noreferrer">View the transaction.</a></p><h2 id="sharing" tabindex="-1">Sharing <a class="header-anchor" href="#sharing" aria-label="Permalink to &quot;Sharing&quot;">​</a></h2><p>Each card has a read-only verify view at <code>/verify/&lt;address&gt;</code>. It resolves live: Dojang status, active up.id, current card fields, and the version history. It needs no passkey and no session, so it is safe to share.</p>',12)])])}const f=a(i,[["render",s]]);export{p as __pageData,f as default};
